public class Computer {
    private final String hdd;
    private final String ram;
    private final boolean hasGraphics;
    private final boolean hasBluetooth;

    private Computer(Builder builder) {   // private — only Builder can call this
        this.hdd          = builder.hdd;
        this.ram          = builder.ram;
        this.hasGraphics  = builder.hasGraphics;
        this.hasBluetooth = builder.hasBluetooth;
    }

    public static class Builder {
        private final String hdd;   // required
        private final String ram;   // required
        private boolean hasGraphics  = false;   // optional
        private boolean hasBluetooth = false;   // optional

        public Builder(String hdd, String ram) {
            this.hdd = hdd;
            this.ram = ram;
        }

        public Builder setGraphics(boolean val)  { this.hasGraphics  = val; return this; }
        public Builder setBluetooth(boolean val) { this.hasBluetooth = val; return this; }

        public Computer build() {
            // Validation can go here
            return new Computer(this);
        }
    }
}

// CLIENT — fluent and self-documenting
Computer myComp = new Computer.Builder("1TB", "32GB")
    .setGraphics(true)
    .setBluetooth(true)
    .build();
// myComp is fully formed and immutable — no setters exposed

public class SqlQuery {
    private final String table;
    private final List<String> columns;
    private final List<String> whereClauses;
    private final String orderBy;
    private final int limit;

    private SqlQuery(Builder b) {
        this.table        = b.table;
        this.columns      = b.columns;
        this.whereClauses = b.whereClauses;
        this.orderBy      = b.orderBy;
        this.limit        = b.limit;
    }

    public static class Builder {
        private String table;
        private List<String> columns      = new ArrayList<>();
        private List<String> whereClauses = new ArrayList<>();
        private String orderBy;
        private int limit;

        public Builder(String table) { this.table = table; }

        public Builder select(String col)   { columns.add(col);      return this; }
        public Builder where(String cond)   { whereClauses.add(cond); return this; }  // called multiple times
        public Builder orderBy(String col)  { this.orderBy = col;     return this; }
        public Builder limit(int n)         { this.limit = n;          return this; }

        public SqlQuery build() {
            if (columns.isEmpty()) columns.add("*");
            return new SqlQuery(this);
        }
    }
}

// CLIENT — reads like a DSL
SqlQuery.Builder builder = new SqlQuery.Builder("users")
    .select("id").select("username").select("email")
    .where("status = 'active'")
    .orderBy("created_at DESC")
    .limit(10);

// Conditional construction — impossible with standard constructors
boolean filterByAdmin = true;
if (filterByAdmin) builder.where("role = 'ADMIN'");

SqlQuery query = builder.build();
// SELECT id, username, email FROM users
// WHERE status = 'active' AND role = 'ADMIN'
// ORDER BY created_at DESC LIMIT 10

// BUILDER INTERFACE
interface Builder {
    void reset();
    void setSeats(int n);
    void setEngine(String engine);
    void setTripComputer(boolean hasTC);
    void setGPS(boolean hasGPS);
}

// CONCRETE BUILDER 1 — assembles a physical Car
class CarBuilder implements Builder {
    private Car car;
    public CarBuilder() { reset(); }
    public void reset()                        { this.car = new Car(); }
    public void setSeats(int n)                { car.seats = n; }
    public void setEngine(String e)            { car.engine = e; }
    public void setTripComputer(boolean hasTC) { car.hasTripComputer = hasTC; }
    public void setGPS(boolean hasGPS)         { car.hasGPS = hasGPS; }
    public Car getProduct() { Car r = car; reset(); return r; }
}

// CONCRETE BUILDER 2 — writes a documentation Manual
class CarManualBuilder implements Builder {
    private Manual manual;
    public CarManualBuilder() { reset(); }
    public void reset()                        { this.manual = new Manual(); }
    public void setSeats(int n)                { manual.addSection("Safety: " + n + " seats."); }
    public void setEngine(String e)            { manual.addSection("Engine: " + e + " specs."); }
    public void setTripComputer(boolean hasTC) { if (hasTC) manual.addSection("Trip Computer: see section 4."); }
    public void setGPS(boolean hasGPS)         { if (hasGPS) manual.addSection("GPS: Navigation guide."); }
    public Manual getProduct() { Manual r = manual; reset(); return r; }
}

// DIRECTOR — knows the recipe, not the materials
class Director {
    public void constructSportsCar(Builder builder) {
        builder.reset();
        builder.setSeats(2);
        builder.setEngine("SportEngine");
        builder.setTripComputer(true);
        builder.setGPS(true);
    }
    public void constructSUV(Builder builder) {
        builder.reset();
        builder.setSeats(7);
        builder.setEngine("DieselEngine");
        builder.setTripComputer(false);
        builder.setGPS(true);
    }
}

// CLIENT
Director director = new Director();
CarBuilder carBuilder = new CarBuilder();
director.constructSportsCar(carBuilder);
Car car = carBuilder.getProduct();

CarManualBuilder manualBuilder = new CarManualBuilder();
director.constructSportsCar(manualBuilder);   // same method!
Manual manual = manualBuilder.getProduct();
// Manual is GUARANTEED to describe a sports car — cannot drift out of sync

interface DocumentBuilder {
    void reset();
    void buildTitle(String text);
    void buildSection(String header, String body);
    void buildFooter(String text);
    Document getResult();
}

class HtmlBuilder implements DocumentBuilder {
    private Document doc;
    public void reset()                              { doc = new Document(); }
    public void buildTitle(String t)                 { doc.add("<h1>" + t + "</h1>\n"); }
    public void buildSection(String h, String b)     { doc.add("<h2>" + h + "</h2><p>" + b + "</p>\n"); }
    public void buildFooter(String t)                { doc.add("<footer>" + t + "</footer>"); }
    public Document getResult()                      { return doc; }
}

class MarkdownBuilder implements DocumentBuilder {
    private Document doc;
    public void reset()                              { doc = new Document(); }
    public void buildTitle(String t)                 { doc.add("# " + t + "\n"); }
    public void buildSection(String h, String b)     { doc.add("## " + h + "\n" + b + "\n"); }
    public void buildFooter(String t)                { doc.add("---\n*" + t + "*"); }
    public Document getResult()                      { return doc; }
}

class DocumentDirector {
    public void constructStandardReport(DocumentBuilder builder) {
        builder.reset();
        builder.buildTitle("Annual Financial Report");
        builder.buildSection("Executive Summary", "The company grew by 20%...");
        builder.buildSection("Analysis", "Detailed metrics show...");
        builder.buildFooter("Confidential - 2026");
    }
}

// CLIENT — same director, two formats
DocumentDirector director = new DocumentDirector();
HtmlBuilder htmlBuilder = new HtmlBuilder();
MarkdownBuilder mdBuilder = new MarkdownBuilder();

director.constructStandardReport(htmlBuilder);
director.constructStandardReport(mdBuilder);
// Both outputs describe the same report — just in different formats

