public class HttpRequest {
    private final String url;
    private final String method;
    private final String body;
    private final int timeout;
    private final Map<String,String> headers;

    private HttpRequest(Builder b) {
        this.url = b.url; this.method = b.method;
        this.body = b.body; this.timeout = b.timeout;
        this.headers = Collections.unmodifiableMap(new HashMap<>(b.headers));
    }

    public static class Builder {
        private final String url, method;
        private String body = null;
        private int timeout = 30;
        private Map<String,String> headers = new HashMap<>();

        public Builder(String url, String method) { this.url = url; this.method = method; }
        public Builder body(String b)              { this.body = b; return this; }
        public Builder timeout(int s)              { this.timeout = s; return this; }
        public Builder header(String k, String v)  { headers.put(k, v); return this; }

        public HttpRequest build() {
            if (url == null || url.isEmpty())
                throw new IllegalArgumentException("URL cannot be empty.");
            return new HttpRequest(this);
        }
    }
}

// Client
HttpRequest req = new HttpRequest.Builder("https://api.example.com/users", "POST")
    .body("{\"name\": \"Alice\"}")
    .timeout(60)
    .header("Content-Type", "application/json")
    .build();
